import{_ as r,r as i,o as s,c as h,a as t,d as o,F as d,b as n,e}from"./app.07731f7d.js";import{_ as c}from"./image.b2036fc0.js";const l={},m=n('<h1 id="my-thoughts-on-the-chat-reporting-feature-for-minecraft-java-edition" tabindex="-1"><a class="header-anchor" href="#my-thoughts-on-the-chat-reporting-feature-for-minecraft-java-edition" aria-hidden="true">#</a> My Thoughts on the Chat Reporting Feature for Minecraft: Java Edition</h1><h2 id="funny-how-the-two-most-controversial-updates-for-minecraft-java-edition-end-in-9-anyone-fancy-a-1-29-update" tabindex="-1"><a class="header-anchor" href="#funny-how-the-two-most-controversial-updates-for-minecraft-java-edition-end-in-9-anyone-fancy-a-1-29-update" aria-hidden="true">#</a> Funny how the two most controversial updates for Minecraft: Java Edition end in 9. Anyone fancy a 1.29 update?</h2><p>Author: SmokeyStack</p><p>Published: 1st July 2022</p><p><img src="'+c+'" alt=""></p><h2 id="background" tabindex="-1"><a class="header-anchor" href="#background" aria-hidden="true">#</a> Background</h2>',6),u=e("On 15/06/2022, "),p={href:"https://www.minecraft.net/en-us/article/minecraft-snapshot-22w24a",target:"_blank",rel:"noopener noreferrer"},f=e("Snapshot 22W24A"),y=e(" was released bringing a welcoming change that is allay duping. However, in the same snapshot, the ability to report chat was introduced. It allows users to select individual chat messages that contain objectionable content, as well as the category of the report, and send it to the moderation team to take action. This has stirred quite the controversy among the Java community."),g=t("h2",{id:"my-thoughts-on-this-feature",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#my-thoughts-on-this-feature","aria-hidden":"true"},"#"),e(" My Thoughts on this Feature")],-1),w=e("Finally! Parity wooo! Jokes aside(or is it), I am finally glad that Mojang is taking action to enforce their "),_={href:"https://help.minecraft.net/hc/en-us/articles/7317376541197-Minecraft-Java-Edition-Player-Chat-Reporting-FAQ",target:"_blank",rel:"noopener noreferrer"},b=e("Community Guidelines"),v=e(" and the "),k={href:"https://www.xbox.com/legal/community-standards",target:"_blank",rel:"noopener noreferrer"},M=e("Xbox Community Standards"),I=e(". Far too long have Java servers gotten off scott-free and I am down for anything to make multiplayer less toxic. However, after discussing with some people regarding this feature, I still support it, however, it should be an optional thing that can be configured via a server config file. Do note however there are mods that can disabled chat signing which in turn disables the report feature. Bedrock has had moderation for two years now and the game is still the same. I believe nothing will change about Java as well."),j=t("h2",{id:"my-thoughts-on-mojang",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#my-thoughts-on-mojang","aria-hidden":"true"},"#"),e(" My Thoughts on Mojang")],-1),T=t("p",null,"Mojang lately has not been on their A-game when it comes to communication. In my opinion, it started when they announced that fireflies and updated birch forest were not coming to the The Wild Update, 28 days before it was released. This lack of communication led to so many dissapointments as the features they were hyped for months were cancelled. When it came to the chat report feature they just mentioned it in a changelog rather a whole in depth article like they did with the account migration.",-1),x=t("p",null,"On the day that 1.19.1 was originally set to release, I was informed that the update would be delayed not by an article, or a tweet, but rather a private conversation with a Community Manager. As the day progressed, players asked where the update was and I told them it was delayed. One player asked where my source was to which I responded it was a message from the aforementioned Community Manager. Understandably they were angry that Mojang didn't officially announce the delay. It wasn't until 21 hours later, since I was informed about the delay, that Mojang officially tweeted that 1.19.1 would be delayed.",-1),A=e("Fortunately, Mojang has posted a "),C={href:"https://help.minecraft.net/hc/en-us/articles/7317376541197-Minecraft-Java-Edition-Player-Chat-Reporting-FAQ",target:"_blank",rel:"noopener noreferrer"},W=e("FAQ"),E=e(" page and a "),F={href:"https://www.minecraft.net/en-us/article/addressing-player-chat-reporting-tool",target:"_blank",rel:"noopener noreferrer"},B=e("blog post"),J=e(" addressing this feature. Better late than never I suppose."),H=n('<p>The serious lack of communication in advance is creating more distrust between Mojang and the community. All I ask for is better communication so something like this won&#39;t happen again.</p><h2 id="my-reaction-to-the-community" tabindex="-1"><a class="header-anchor" href="#my-reaction-to-the-community" aria-hidden="true">#</a> My Reaction to the Community</h2><p>If you didn&#39;t know, I am a Community Ambassador for the Official Minecraft Discord server. We assist the moderators with task and in no way affiliated with Mojang/Microsoft nor are we paid. We are all volunteers. When the feature came out, a new channel was created to compile feedback the community had about the report system.</p><p><em>Looks through notes</em> Do I have to talk about this? Ok, story time! WHAT. A. WEEK. IT. HAS. BEEN. When the channel first opened I lurked in there to make sure the members were being civil, they were doing the opposite of that. There was arguing, rudeness, and disrespect amongst each other. When I and other Community Ambassadors intervened to keep chat civil, people started harassing us. They called us shills, bootlickers, and spammed clown and nerd emojis. It was so bad that I had to close my DMs for the server in a long time because I was afraid people would harass me in DMs. Anytime someone asked me for my opinion and I told them I support this feature, they would ask, &quot;How much is Microsoft paying you?&quot; even though we told them time and time again that we are not affiliated with Mojang/Microsoft.</p><p>That wasn&#39;t even the worst part. I have never seen the community stoop to such low levels since Caves and Cliffs was announced to be split. You had people who started defending slurs and that it&#39;s ok to be racist because it&#39;s their server and they can do whatever they want. Then you had people who started supporting piracy in the official Discord server where the developers of the game could see their messages mind you. Their reasoning? Because it&#39;s Microsoft&#39;s property so it&#39;s ok to pirate things.</p><p>They also proceeded to spam the following:</p><ul><li>1.19.84</li><li>1984</li><li>#saveminecraft</li><li>#removereportfeature</li></ul><p>None of this is <em>constructive</em> feedback, it&#39;s just spam. The channel was created for <em>constructive</em> feedback for the developers. So when I started deleting these messages they harassed us even more, accusing us of censorship and violating their freedom of speech. Oh boy, freedom of speech is a whole can of worms that I will not be diving into. Regardless of what they called us, we still went ahead and helped compile a list of feedback and concerns the community had and relayed it to the aforementioned Community Manager who relayed it to the appropriate teams. We were doing beyond what we were expected to. We didn&#39;t need to compile feedback, yet we did anyways and they were ungrateful. However, to those who did provide constructive feedback, you have my respect, and we need more of you in the world.</p><h2 id="conclusion" tabindex="-1"><a class="header-anchor" href="#conclusion" aria-hidden="true">#</a> Conclusion</h2><p>This is just a block game. There is no need to be rude or upset at each other over it. Both the community and Mojang is to blame. The community for the harassment to each other, and Mojang for the lack of communication. Hopefully this will all blow over and both the community and Mojang can learn from their mistakes and improve from them.</p>',10);function S(D,N){const a=i("ExternalLinkIcon");return s(),h(d,null,[m,t("p",null,[u,t("a",p,[f,o(a)]),y]),g,t("p",null,[w,t("a",_,[b,o(a)]),v,t("a",k,[M,o(a)]),I]),j,T,x,t("p",null,[A,t("a",C,[W,o(a)]),E,t("a",F,[B,o(a)]),J]),H],64)}var P=r(l,[["render",S],["__file","chat_report_thoughts.html.vue"]]);export{P as default};
